#include <stdio.h>
int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int canBeEqual = (360 % N == 0) ? 1 : 0;
        int canBeMade = 0;
        for (int i = 1; i <= 360; i++) {
            if (360 % i == 0) {
                int sum = 0;
                for (int j = i; j <= 360; j += i) {
                    sum++;
                    if (sum == N) {
                        canBeMade = 1;
                        break;
                    }
                }
                if (canBeMade) break;
            }
        }
        int canBeDifferent = (N <= 96) ? 1 : 0;
        printf("%c %c %c\n", canBeEqual ? 'y' : 'n', canBeMade ? 'y' : 'n', canBeDifferent ? 'y' : 'n');
    }
    return 0;
}

