import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int canBeEqual = (360 % N == 0) ? 1 : 0;
            int canBeMade = 0;
            for (int i = 1; i <= 360; i++) {
                if (360 % i == 0) {
                    int sum = 0;
                    for (int j = i; j <= 360; j += i) {
                        sum++;
                        if (sum == N) {
                            canBeMade = 1;
                            break;
                        }
                    }
                    if (canBeMade > 0) break;
                }
            }
            int canBeDifferent = (N <= 96) ? 1 : 0;
            System.out.println((canBeEqual == 1 ? "y" : "n") + " " + (canBeMade == 1 ? "y" : "n") + " " + (canBeDifferent == 1 ? "y" : "n"));
        }
    }
}

